#include<bits/stdc++.h>
using namespace std;

const int N = 5e5 + 5;

vector<int> e[N];

vector<int> dcc[N];

int s[N], low[N], dfn[N];
int dfncnt, tp, dcc_cnt;

void tarjan(int u, int fa)
{
    s[++tp] = u, low[u] = dfn[u] = ++dfncnt;
    int son = 0;
    for(int v : e[u])
    {
        if(!dfn[v])
        {
            son++;
            tarjan(v, u), low[u] = min(low[u], low[v]);
            if(low[v] >= dfn[u])
            {
                int id = ++dcc_cnt;
                while(s[tp + 1] != v)
                    dcc[id].push_back(s[tp--]);
                dcc[id].push_back(u);
            }
        }
        else if(v != fa)
            low[u] = min(low[u], dfn[v]);
    }
    if(u == fa && son == 0)
        dcc[++dcc_cnt].push_back(u);
}

int main()
{
    int n, m;
    cin >> n >> m;
    for(int i = 1; i <= m; i++)
    {
        int x, y;
        cin >> x >> y;
        e[x].push_back(y);
        e[y].push_back(x);
    }
    for(int i = 1; i <= n; i++)
        if(!dfn[i]) tarjan(i, i);
    cout << dcc_cnt << '\n';
    for(int i = 1; i <= dcc_cnt; i++)
    {
        cout << dcc[i].size() << ' ';
        for(int x : dcc[i])
            cout << x << ' ';
        cout << '\n';
    }
    return 0;
}
